mapper.select:
select


where ep.experience_program_status = 'recruiting'
order by
    case
        when ep.experience_program_recruitment_count <= 0 then 999999
        else coalesce(ap.applicant_count, 0) / cast(ep.experience_program_recruitment_count as decimal(10, 2))
    end asc,
    ep.experience_program_deadline asc,
    ep.id desc
limit #{limit}
